# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 00 HTML 시각화 생성기
# 역할: 앞선 Data Analysis 결과를 MongoDB result_ref로 복원하고 HTML/SVG 차트를 만든 뒤 Report API 링크를 발급합니다.
# 주요 입력: 사용자 질문, upstream_result_ref, MongoDB 연결 정보, Report API 주소·TTL, 최대 차트 행 수
# 주요 출력: 차트 파일이 첨부된 Message, visualization.result.v1 API 응답
# 처리 흐름: 요청·세션 검증 -> 결과 행 복원 -> HTML/SVG 생성 -> Langflow 저장 -> Report API 게시 -> 절대 URL 반환
# 유지보수 포인트: 원본 행과 HTML 본문은 API/Workflow payload에 넣지 않고 검증된 링크 descriptor만 전달합니다.
# =============================================================================

from __future__ import annotations

import asyncio
import html
import json
import re
import urllib.error
import urllib.request
import uuid
from datetime import datetime
from importlib import import_module
from math import isfinite
from typing import Any
from urllib.parse import urlsplit

from lfx.custom.custom_component.component import Component
from lfx.io import HandleInput, MessageTextInput, Output, StrInput
from lfx.schema.data import Data
from lfx.schema.message import Message


CONTRACT_VERSION = "visualization.result.v1"
DEFAULT_REPORT_API_URL = "http://127.0.0.1:8010"
DEFAULT_REPORT_TTL_HOURS = 24
MAX_REPORT_TTL_HOURS = 24 * 7
REPORT_API_TIMEOUT_SECONDS = 30
MAX_REPORT_RESPONSE_BYTES = 64 * 1024
DEFAULT_DATABASE = "datagov"
DEFAULT_COLLECTION = "agent_v4_result_store"
DEFAULT_MAX_CHART_ROWS = 500
MAX_CHART_ROWS = 5_000
MAX_HTML_BYTES = 2_000_000
MAX_RESULT_REF_CHARS = 512
MAX_QUESTION_CHARS = 4_000
MAX_ERROR_CHARS = 500
MAX_PUBLIC_URL_CHARS = 2_048
MAX_REPORT_ID_CHARS = 160
SERIES_LIMIT = 3
SVG_WIDTH = 1_000
SVG_HEIGHT = 560
PLOT_LEFT = 86
PLOT_RIGHT = 950
PLOT_TOP = 54
PLOT_BOTTOM = 470
COLORS = ("#2563eb", "#dc2626", "#059669")
DATE_FORMATS = ("%Y%m%d", "%Y-%m-%d", "%Y/%m/%d", "%Y-%m-%d %H:%M:%S", "%Y-%m-%dT%H:%M:%S")
DATE_COLUMN_TOKENS = ("DATE", "_DT", "DT_", "WORK_DT", "BASE_DT", "일자", "날짜", "시간")
METRIC_COLUMN_TOKENS = (
    "PRODUCTION",
    "WIP",
    "QTY",
    "COUNT",
    "CNT",
    "UPH",
    "RATE",
    "RATIO",
    "AMOUNT",
    "생산",
    "재공",
    "수량",
    "실적",
    "계획",
    "달성률",
    "비율",
    "건수",
)


# 함수 설명: 임의 값을 앞뒤 공백이 제거된 문자열로 안전하게 바꿉니다.
def _text(value: Any) -> str:
    return "" if value is None else str(value).strip()


# 함수 설명: 사용자·오류 문자열이 계약 상한을 넘지 않도록 말줄임 처리합니다.
def _clip(value: Any, limit: int) -> str:
    text = _text(value)
    return text if len(text) <= limit else text[: max(0, limit - 1)].rstrip() + "…"


# 함수 설명: 시각화 오류와 경고를 공통 type/message 구조로 만듭니다.
def _issue(issue_type: str, message: Any) -> dict[str, str]:
    return {"type": _clip(issue_type, 100), "message": _clip(message, MAX_ERROR_CHARS)}


# 함수 설명: Langflow Message 또는 일반 값에서 질문과 세션 ID를 추출합니다.
def _message_parts(value: Any) -> tuple[str, str]:
    data = getattr(value, "data", None)
    data = data if isinstance(data, dict) else {}
    question = _text(getattr(value, "text", None) or data.get("text") or value)
    session_id = _text(getattr(value, "session_id", None) or data.get("session_id"))
    return _clip(question, MAX_QUESTION_CHARS), session_id


# 함수 설명: 문자열 또는 data_ref 객체에서 MongoDB 문서 식별자를 꺼냅니다.
def _ref_id(value: Any) -> str:
    if hasattr(value, "model_dump"):
        value = value.model_dump()
    if isinstance(value, dict):
        value = value.get("ref_id") or value.get("result_ref") or value.get("data_ref") or value.get("_id")
    return _text(value)


# 함수 설명: 화면 문자열 입력을 지정된 최소·최대 범위의 정수로 제한합니다.
def _bounded_int(value: Any, default: int, lower: int, upper: int) -> int:
    try:
        parsed = int(float(_text(value))) if _text(value) else default
    except (TypeError, ValueError, OverflowError):
        parsed = default
    return max(lower, min(parsed, upper))


# 함수 설명: 결과 행의 key 등장 순서를 유지하면서 전체 컬럼 목록을 만듭니다.
def _columns_from_rows(rows: list[dict[str, Any]]) -> list[str]:
    columns: list[str] = []
    for row in rows:
        for key in row:
            column = _text(key)
            if column and column not in columns:
                columns.append(column)
    return columns


# 함수 설명: 컬럼명이 일자·시간 축을 나타내는지 이름 규칙으로 판정합니다.
def _is_date_column(column: str) -> bool:
    normalized = column.upper().replace(" ", "_")
    return any(token in normalized for token in DATE_COLUMN_TOKENS)


# 함수 설명: bool·빈 값을 제외하고 차트에 사용할 수 있는 유한 실수로 변환합니다.
def _to_number(value: Any) -> float | None:
    if value is None or isinstance(value, bool):
        return None
    if isinstance(value, (int, float)):
        number = float(value)
        return number if isfinite(number) else None
    text = _text(value).replace(",", "")
    if text.endswith("%"):
        text = text[:-1].strip()
    if not re.fullmatch(r"[-+]?(?:\d+(?:\.\d*)?|\.\d+)", text):
        return None
    try:
        number = float(text)
    except (TypeError, ValueError, OverflowError):
        return None
    return number if isfinite(number) else None


# 함수 설명: 선택된 수량 지표의 NULL·빈 문자열은 데이터 분석 출력 계약과 맞춰 0으로 표시합니다.
def _chart_number(value: Any) -> float | None:
    if value is None or (isinstance(value, str) and not value.strip()):
        return 0.0
    return _to_number(value)


# 함수 설명: 각 컬럼의 비어 있지 않은 값 중 대부분이 숫자로 변환되는 컬럼만 수치 축 후보로 선택합니다.
def _numeric_columns(rows: list[dict[str, Any]], columns: list[str]) -> list[str]:
    numeric: list[str] = []
    for column in columns:
        if _is_date_column(column):
            continue
        nonempty = [row.get(column) for row in rows if row.get(column) not in (None, "")]
        if not nonempty:
            normalized = column.upper().replace(" ", "_")
            if any(token in normalized for token in METRIC_COLUMN_TOKENS):
                numeric.append(column)
            continue
        converted = sum(_to_number(value) is not None for value in nonempty)
        if converted > 0 and converted / len(nonempty) >= 0.8:
            numeric.append(column)
    return numeric


# 함수 설명: 질문 본문에 실제 컬럼명이 명시된 경우 원본 컬럼 순서대로 찾아냅니다.
def _explicit_columns(question: str, columns: list[str]) -> list[str]:
    folded = question.casefold()
    return [column for column in columns if column.casefold() in folded]


# 함수 설명: 질문과 제조 지표 명칭을 기준으로 수치 컬럼의 기본 우선순위를 계산합니다.
def _metric_score(column: str, question: str, index: int) -> tuple[int, int]:
    normalized = column.upper().replace(" ", "_")
    score = 100 if column.casefold() in question.casefold() else 0
    for rank, token in enumerate(METRIC_COLUMN_TOKENS):
        if token in normalized:
            score += len(METRIC_COLUMN_TOKENS) - rank
    if any(token in normalized for token in ("SEQ", "ID", "LEAD", "YEAR", "MONTH")):
        score -= 20
    return score, -index


# 주요 함수: 질문과 결과 스키마만으로 x축, 최대 세 개의 y축 지표, line/bar 유형을 결정합니다.
def select_chart_plan(rows: list[dict[str, Any]], question: str) -> tuple[dict[str, Any], dict[str, str] | None]:
    columns = _columns_from_rows(rows)
    if not columns:
        return {}, _issue("missing_columns", "시각화할 결과 컬럼이 없습니다.")
    numeric = _numeric_columns(rows, columns)
    explicit = _explicit_columns(question, columns)
    date_columns = [column for column in columns if _is_date_column(column)]
    categorical = [column for column in columns if column not in numeric]
    x_candidates = [column for column in explicit if column in date_columns or column in categorical]
    x_candidates.extend(column for column in date_columns if column not in x_candidates)
    x_candidates.extend(column for column in categorical if column not in x_candidates)
    if not x_candidates:
        x_candidates.extend(column for column in columns if column not in numeric)
    x_column = x_candidates[0] if x_candidates else columns[0]
    y_candidates = [column for column in explicit if column in numeric and column != x_column]
    remaining = [column for column in numeric if column != x_column and column not in y_candidates]
    remaining.sort(key=lambda column: _metric_score(column, question, columns.index(column)), reverse=True)
    if not y_candidates and remaining:
        y_candidates.append(remaining.pop(0))
    if any(token in question.casefold() for token in ("비교", "함께", "각각", "모두")):
        y_candidates.extend(remaining[: SERIES_LIMIT - len(y_candidates)])
    y_columns = y_candidates[:SERIES_LIMIT]
    if not y_columns:
        return {}, _issue("missing_numeric_metric", "시각화할 수치 컬럼을 결과에서 찾지 못했습니다.")
    lowered = question.casefold()
    if any(token in lowered for token in ("막대", "bar")):
        chart_type = "bar"
    elif any(token in lowered for token in ("선 그래프", "라인", "line")) or _is_date_column(x_column):
        chart_type = "line"
    else:
        chart_type = "bar"
    title = _clip(question.rstrip(" .?!"), 160) or "데이터 시각화"
    return {"title": title, "chart_type": chart_type, "x_column": x_column, "y_columns": y_columns, "columns": columns}, None


# 함수 설명: 일자 형태의 값을 정렬 가능한 datetime으로 변환하되 원본 표시값은 변경하지 않습니다.
def _temporal_key(value: Any) -> datetime | None:
    text = _text(value)
    if not text:
        return None
    for date_format in DATE_FORMATS:
        try:
            return datetime.strptime(text, date_format)
        except ValueError:
            continue
    try:
        return datetime.fromisoformat(text.replace("Z", "+00:00"))
    except (TypeError, ValueError):
        return None


# 함수 설명: 일자 x축인 경우 해석 가능한 값만 시간순으로 안정 정렬하고 그 외에는 조회 순서를 유지합니다.
def _ordered_rows(rows: list[dict[str, Any]], x_column: str) -> list[dict[str, Any]]:
    if not _is_date_column(x_column):
        return list(rows)
    parsed = [_temporal_key(row.get(x_column)) for row in rows]
    if sum(value is not None for value in parsed) < max(1, int(len(rows) * 0.8)):
        return list(rows)
    indexed = list(enumerate(rows))
    maximum = datetime.max
    indexed.sort(key=lambda item: (parsed[item[0]] or maximum, item[0]))
    return [row for _, row in indexed]


# 함수 설명: 행이 화면 상한을 넘으면 첫·끝을 포함한 균등 간격으로 점을 줄여 SVG 크기를 제한합니다.
def _sample_rows(rows: list[dict[str, Any]], limit: int) -> tuple[list[dict[str, Any]], bool]:
    if len(rows) <= limit:
        return list(rows), False
    if limit <= 1:
        return [rows[0]], True
    indexes = [round(index * (len(rows) - 1) / (limit - 1)) for index in range(limit)]
    return [rows[index] for index in indexes], True


# 함수 설명: 숫자를 불필요한 소수점 없이 축과 표에 표시합니다.
def _format_number(value: float) -> str:
    if abs(value - round(value)) < 1e-9:
        return f"{round(value):,}"
    return f"{value:,.4f}".rstrip("0").rstrip(".")


# 함수 설명: SVG 좌표 계산용 전체 수치 범위를 0 포함 형태로 만들고 동일값 범위를 보정합니다.
def _value_range(rows: list[dict[str, Any]], y_columns: list[str]) -> tuple[float, float]:
    values = [number for row in rows for column in y_columns if (number := _chart_number(row.get(column))) is not None]
    minimum = min([0.0, *values]) if values else 0.0
    maximum = max([0.0, *values]) if values else 1.0
    if abs(maximum - minimum) < 1e-12:
        maximum = minimum + 1.0
    return minimum, maximum


# 함수 설명: 실제 수치를 SVG plot 영역의 y 좌표로 변환합니다.
def _y_position(value: float, minimum: float, maximum: float) -> float:
    plot_height = PLOT_BOTTOM - PLOT_TOP
    return PLOT_BOTTOM - ((value - minimum) / (maximum - minimum)) * plot_height


# 함수 설명: 각 행의 x축 중심 좌표를 line 또는 grouped bar 배치에 맞게 계산합니다.
def _x_position(index: int, count: int) -> float:
    plot_width = PLOT_RIGHT - PLOT_LEFT
    return PLOT_LEFT + plot_width / 2 if count <= 1 else PLOT_LEFT + index * plot_width / (count - 1)


# 주요 함수: 외부 JavaScript 없이 선/막대 차트, 축, 범례, 접근성 title을 포함한 inline SVG를 생성합니다.
def render_svg_chart(rows: list[dict[str, Any]], plan: dict[str, Any]) -> str:
    x_column = str(plan["x_column"])
    y_columns = [str(column) for column in plan["y_columns"]]
    minimum, maximum = _value_range(rows, y_columns)
    parts = [
        f'<svg viewBox="0 0 {SVG_WIDTH} {SVG_HEIGHT}" role="img" aria-labelledby="chart-title chart-desc">',
        f'<title id="chart-title">{html.escape(str(plan["title"]))}</title>',
        f'<desc id="chart-desc">{html.escape(x_column)} 기준 {html.escape(", ".join(y_columns))} {plan["chart_type"]} 차트</desc>',
        '<rect width="100%" height="100%" rx="18" fill="#ffffff"/>',
    ]
    for tick in range(6):
        ratio = tick / 5
        value = maximum - (maximum - minimum) * ratio
        y = PLOT_TOP + (PLOT_BOTTOM - PLOT_TOP) * ratio
        parts.append(f'<line x1="{PLOT_LEFT}" y1="{y:.2f}" x2="{PLOT_RIGHT}" y2="{y:.2f}" stroke="#e5e7eb"/>')
        parts.append(f'<text x="{PLOT_LEFT - 12}" y="{y + 4:.2f}" text-anchor="end" class="axis-label">{html.escape(_format_number(value))}</text>')
    parts.append(f'<line x1="{PLOT_LEFT}" y1="{PLOT_TOP}" x2="{PLOT_LEFT}" y2="{PLOT_BOTTOM}" stroke="#64748b"/>')
    parts.append(f'<line x1="{PLOT_LEFT}" y1="{PLOT_BOTTOM}" x2="{PLOT_RIGHT}" y2="{PLOT_BOTTOM}" stroke="#64748b"/>')
    label_step = max(1, (len(rows) + 9) // 10)
    for index, row in enumerate(rows):
        if index % label_step != 0 and index != len(rows) - 1:
            continue
        x = _x_position(index, len(rows))
        label = _clip(row.get(x_column), 18)
        parts.append(f'<text x="{x:.2f}" y="{PLOT_BOTTOM + 28}" text-anchor="middle" class="axis-label">{html.escape(label)}</text>')
    if plan["chart_type"] == "line":
        for series_index, column in enumerate(y_columns):
            color = COLORS[series_index]
            points: list[str] = []
            valid_points: list[tuple[float, float, str, str]] = []
            for index, row in enumerate(rows):
                number = _chart_number(row.get(column))
                if number is None:
                    continue
                x = _x_position(index, len(rows))
                y = _y_position(number, minimum, maximum)
                points.append(f"{x:.2f},{y:.2f}")
                valid_points.append((x, y, _text(row.get(x_column)), _format_number(number)))
            if points:
                parts.append(f'<polyline points="{" ".join(points)}" fill="none" stroke="{color}" stroke-width="3" stroke-linejoin="round" stroke-linecap="round"/>')
            for x, y, x_label, formatted in valid_points:
                tooltip = html.escape(f"{x_label} · {column}: {formatted}")
                parts.append(f'<circle cx="{x:.2f}" cy="{y:.2f}" r="4.5" fill="{color}"><title>{tooltip}</title></circle>')
    else:
        group_width = max(5.0, (PLOT_RIGHT - PLOT_LEFT) / max(1, len(rows)) * 0.72)
        bar_width = max(2.0, group_width / max(1, len(y_columns)))
        zero_y = _y_position(0.0, minimum, maximum)
        for row_index, row in enumerate(rows):
            center = _x_position(row_index, len(rows))
            group_start = center - group_width / 2
            for series_index, column in enumerate(y_columns):
                number = _chart_number(row.get(column))
                if number is None:
                    continue
                value_y = _y_position(number, minimum, maximum)
                y = min(zero_y, value_y)
                height = max(1.0, abs(zero_y - value_y))
                x = group_start + series_index * bar_width
                tooltip = html.escape(f"{_text(row.get(x_column))} · {column}: {_format_number(number)}")
                parts.append(f'<rect x="{x:.2f}" y="{y:.2f}" width="{max(1.0, bar_width - 2):.2f}" height="{height:.2f}" rx="2" fill="{COLORS[series_index]}"><title>{tooltip}</title></rect>')
    legend_x = PLOT_LEFT
    for index, column in enumerate(y_columns):
        x = legend_x + index * 240
        parts.append(f'<rect x="{x}" y="18" width="14" height="14" rx="3" fill="{COLORS[index]}"/>')
        parts.append(f'<text x="{x + 21}" y="30" class="legend-label">{html.escape(column)}</text>')
    parts.append(f'<text x="{(PLOT_LEFT + PLOT_RIGHT) / 2:.2f}" y="{SVG_HEIGHT - 18}" text-anchor="middle" class="axis-title">{html.escape(x_column)}</text>')
    parts.append("</svg>")
    return "".join(parts)


# 함수 설명: 차트 아래 접근성 표에 표시할 x/y 셀만 안전하게 HTML로 변환합니다.
def _result_table(rows: list[dict[str, Any]], plan: dict[str, Any]) -> str:
    columns = [str(plan["x_column"]), *[str(column) for column in plan["y_columns"]]]
    header = "".join(f"<th>{html.escape(column)}</th>" for column in columns)
    body_rows: list[str] = []
    for row in rows:
        cells: list[str] = []
        for column in columns:
            number = _chart_number(row.get(column)) if column in plan["y_columns"] else None
            value = _format_number(number) if number is not None else _text(row.get(column))
            cells.append(f"<td>{html.escape(value)}</td>")
        body_rows.append("<tr>" + "".join(cells) + "</tr>")
    return f"<div class=\"table-wrap\"><table><thead><tr>{header}</tr></thead><tbody>{''.join(body_rows)}</tbody></table></div>"


# 주요 함수: inline CSS·SVG·데이터 표만 포함하고 외부 CDN이나 script가 없는 완전한 HTML 문서를 만듭니다.
def render_html_document(rows: list[dict[str, Any]], plan: dict[str, Any]) -> str:
    svg = render_svg_chart(rows, plan)
    table = _result_table(rows, plan)
    title = html.escape(str(plan["title"]))
    subtitle = html.escape(f"{plan['x_column']} 기준 · {', '.join(plan['y_columns'])} · {len(rows):,}개 점")
    return f"""<!doctype html>
<html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{title}</title>
<style>
